def calculate_segmentation_mask(x, y, x1, y1, x2, y2):
    height = y2 - y1
    width = x2 - x1

    segmentation_mask = [
        [1 if (y1 <= row < y2 and x1 <= col < x2 and (x, y) == (col, row)) else 0 for col in range(width)]
        for row in range(height)
    ]

    return segmentation_mask
